  /**
   * Verifies that the lock file hash matches an expected value
   * Useful for deployment pipelines to ensure no tampering
   */
  verifyLockFileIntegrity(expectedHash) {
    if (!fs.existsSync(this.packageLockPath)) {
      return { verified: false, reason: 'Lock file does not exist' };
    }

    const actualHash = this.computeFileHash(this.packageLockPath);
    const matches = crypto.timingSafeEqual(
      Buffer.from(actualHash, 'hex'),
      Buffer.from(expectedHash, 'hex')
    );

    return {
      verified: matches,
      expectedHash,
      actualHash,
      reason: matches ? 'Hash matches' : 'Hash mismatch - lock file may have been modified'
    };
  }

