// ─────────────────────────────────────────────────────────────────────────────
// CLI Interface
// ─────────────────────────────────────────────────────────────────────────────

function main() {
  const args = process.argv.slice(2);
  const command = args[0];
  const projectRoot = args[1] || process.cwd();

  if (!command || command === '--help' || command === '-h') {
    console.log(`
Package Lock Manager - Ensure reproducible builds

Usage: node package-lock-manager.js <command> [project-root]

Commands:
  validate        Validate package.json and package-lock.json
  generate        Generate a fresh package-lock.json
  clean-install   Run npm ci for reproducible installs
  update          Update all packages within semver ranges
  audit-fix       Run npm audit fix
  backup          Create a backup of the current lock file
  list-backups    List available backups
  restore         Restore from a backup (provide filename as 3rd arg)
  compare         Compare two lock files (provide paths as 2nd and 3rd args)
  ci-report       Generate a comprehensive CI/CD report
  hash            Print the SHA-256 hash of the lock file
  verify          Verify lock file hash (provide expected hash as 2nd arg)
  npmrc           Generate recommended .npmrc configuration
  docs            Print comprehensive documentation

Examples:
  node package-lock-manager.js validate
  node package-lock-manager.js generate ./my-project
  node package-lock-manager.js clean-install
  node package-lock-manager.js compare ./old-lock.json ./new-lock.json
  node package-lock-manager.js verify abc123def456...
  node package-lock-manager.js docs
`);
    process.exit(0);
  }

  try {
    switch (command) {
      case 'validate': {
        const manager = new PackageLockManager(projectRoot);
        const pkgResult = manager.validatePackageJson();
        console.log('\n📦 package.json:', pkgResult.valid ? '✅ Valid' : '❌ Invalid');

        const lockResult = manager.validateLockFile();
        console.log('🔒 package-lock.json:', lockResult.valid ? '✅ Valid' : '❌ Issues found');

        if (lockResult.issues.length > 0) {
          console.log('\nIssues:');
          lockResult.issues.forEach(i => console.log(`  ❌ ${i}`));
        }
        if (lockResult.recommendations.length > 0) {
          console.log('\nRecommendations:');
          lockResult.recommendations.forEach(r => console.log(`  💡 ${r}`));
        }

        const treeResult = manager.verifyDependencyTree();
        console.log('\n🌳 Dependency tree:', treeResult.consistent ? '✅ Consistent' : '❌ Inconsistent');
        if (treeResult.problems && treeResult.problems.length > 0) {
          treeResult.problems.forEach(p => console.log(`  ⚠️  ${p}`));
        }

        process.exit(lockResult.valid && treeResult.consistent ? 0 : 1);
        break;
      }

      case 'generate': {
        const manager = new PackageLockManager(projectRoot);
        const result = manager.generateLockFile({ ignoreScripts: true });
        console.log('✅ Lock file generated.');
        console.log(`   Hash: ${result.hash}`);
        console.log(`   Version: ${result.lockfileVersion}`);
        break;
      }

      case 'clean-install': {
        const manager = new PackageLockManager(projectRoot);
        manager.cleanInstall();
        console.log('✅ Clean install completed.');
        break;
      }

      case 'update': {
        const manager = new PackageLockManager(projectRoot);
        const packages = args.slice(2);
        const result = manager.updatePackages(packages);
        console.log('✅ Update completed.');
        console.log(`   Hash: ${result.hash}`);
        break;
      }

      case 'audit-fix': {
        const manager = new PackageLockManager(projectRoot);
        const result = manager.auditFix();
        console.log(result.success ? '✅ Audit fix completed.' : '❌ Audit fix had issues.');
        break;
      }

      case 'backup': {
        const manager = new PackageLockManager(projectRoot);
        const backupPath = manager.createBackup('cli');
        console.log(`✅ Backup created: ${backupPath}`);
        break;
      }

      case 'list-backups': {
        const manager = new PackageLockManager(projectRoot);
        const backups = manager.listBackups();
        if (backups.length === 0) {
          console.log('No backups found.');
        } else {
          console.log(`\nAvailable backups (${backups.length}):\n`);
          backups.forEach((b, i) => {
            console.log(`  ${i + 1}. ${b.filename}`);
            console.log(`     Size: ${(b.size / 1024).toFixed(1)} KB | Hash: ${b.hash.substring(0, 16)}...`);
          });
        }
        break;
      }

      case 'restore': {
        const manager = new PackageLockManager(projectRoot);
        const filename = args[2];
        if (!filename) {
          console.error('Please provide a backup filename. Use "list-backups" to see available backups.');
          process.exit(1);
        }
        const result = manager.restoreBackup(filename);
        console.log(`✅ Restored from: ${result.restoredFrom}`);
        break;
      }

      case 'compare': {
        const fileA = args[1];
        const fileB = args[2];
        if (!fileA || !fileB) {
          console.error('Usage: compare <file-a> <file-b>');
          process.exit(1);
        }
        const manager = new PackageLockManager(process.cwd());
        const diff = manager.compareLockFiles(fileA, fileB);
        console.log('\n📊 Lock File Comparison:\n');
        console.log(`  Added:     ${diff.summary.added}`);
        console.log(`  Removed:   ${diff.summary.removed}`);
        console.log(`  Changed:   ${diff.summary.changed}`);
        console.log(`  Unchanged: ${diff.summary.unchanged}`);
        console.log(`  Total:     ${diff.summary.total}`);

        if (Object.keys(diff.added).length > 0) {
          console.log('\n  ➕ Added:');
          Object.entries(diff.added).forEach(([pkg, ver]) => console.log(`     ${pkg}@${ver}`));
        }
        if (Object.keys(diff.removed).length > 0) {
          console.log('\n  ➖ Removed:');
          Object.entries(diff.removed).forEach(([pkg, ver]) => console.log(`     ${pkg}@${ver}`));
        }
        if (Object.keys(diff.changed).length > 0) {
          console.log('\n  🔄 Changed:');
          Object.entries(diff.changed).forEach(([pkg, { from, to }]) =>
            console.log(`     ${pkg}: ${from} → ${to}`)
          );
        }
        break;
      }

      case 'ci-report': {
        const manager = new PackageLockManager(projectRoot);
        const report = manager.generateCIReport();
        console.log(JSON.stringify(report, null, 2));
        process.exit(report.recommendations.some(r => r.startsWith('CRITICAL')) ? 1 : 0);
        break;
      }

      case 'hash': {
        const manager = new PackageLockManager(projectRoot);
        if (!fs.existsSync(manager.packageLockPath)) {
          console.error('package-lock.json not found.');
          process.exit(1);
        }
        const hash = manager.computeFileHash(manager.packageLockPath);
        console.log(hash);
        break;
      }

      case 'verify': {
        const expectedHash = args[1];
        if (!expectedHash) {
          console.error('Usage: verify <expected-hash>');
          process.exit(1);
        }
        const manager = new PackageLockManager(args[2] || process.cwd());
        const result = manager.verifyLockFileIntegrity(expectedHash);
        console.log(result.verified ? '✅ Lock file integrity verified.' : '❌ Lock file integrity check FAILED.');
        console.log(`   Expected: ${result.expectedHash}`);
        console.log(`   Actual:   ${result.actualHash}`);
        process.exit(result.verified ? 0 : 1);
        break;
      }

      case 'npmrc': {
        const manager = new PackageLockManager(projectRoot);
        const result = manager.generateNpmrcConfig({
          ci: args.includes('--ci'),
          write: args.includes('--write'),
          saveExact: true
        });
        console.log('\nRecommended .npmrc configuration:\n');
        console.log(result.content);
        if (args.includes('--write')) {
          console.log(`Written to: ${result.path}`);
        } else {
          console.log('Use --write flag to save to .npmrc');
        }
        break;
      }

      case 'docs': {
        console.log(PackageLockManager.generateDocumentation());
        break;
      }

      default:
        console.error(`Unknown command: ${command}. Use --help for usage information.`);
        process.exit(1);
    }
  } catch (err) {
    console.error(`\n❌ Error: ${err.message}`);
    process.exit(1);
  }
}

// Run CLI if executed directly
if (require.main === module) {
  main();
}

module.exports = PackageLockManager;